import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch7: ScenarioQuestion[] = [
  q("sq-bg7-1",ip,"behavioral","You are passionate about health equity.","How does health equity influence your nursing practice?","I am committed to providing equitable care regardless of a patient's background, insurance status, or social situation. I actively seek to understand social determinants of health that affect my patients, advocate for resources to address health disparities, and challenge biases—including my own—that may affect care delivery. Health equity is not just an ideal; it is a daily practice.","Active health equity commitment in practice.","intermediate"),
  q("sq-bg7-2",ip,"behavioral","You dealt with a difficult family situation that strengthened your nursing skills.","How have personal challenges prepared you for nursing?","Caring for my mother during her cancer treatment while in nursing school taught me empathy from the patient-family perspective. I understood the fear, confusion, and helplessness that families experience. This firsthand experience makes me more compassionate and patient-centered. I know what it feels like to be on the other side of the bedside.","Personal experience enriching professional empathy.","beginner"),
  q("sq-bg7-3",ip,"clinical_judgment","A patient on SSRI antidepressant develops agitation, hyperthermia, and myoclonus.","What syndrome does this presentation suggest?","These symptoms suggest serotonin syndrome—a potentially life-threatening condition caused by excess serotonergic activity. I would stop the offending medication immediately, provide aggressive cooling, administer benzodiazepines for agitation, and notify the provider. Cyproheptadine may be used as a serotonin antagonist. I would monitor vital signs closely and prepare for possible ICU transfer.","Serotonin syndrome recognition and management.","advanced"),
  q("sq-bg7-4",ip,"clinical_judgment","A patient with type 1 diabetes has a blood glucose of 40 and is unconscious.","How would you manage severe hypoglycemia with altered consciousness?","I would not attempt oral glucose in an unconscious patient due to aspiration risk. I would administer IV dextrose 50% (D50) push if IV access is available, or glucagon IM if not. I would position the patient safely, monitor continuously, and recheck glucose in 15 minutes. I would investigate the cause of hypoglycemia and adjust the insulin regimen. I would not leave the patient unattended.","Unconscious hypoglycemia emergency management.","intermediate"),
  q("sq-bg7-5",ip,"clinical_judgment","A patient with pneumonia develops a parapneumonic effusion.","What does fluid accumulation around the lung indicate?","A parapneumonic effusion is fluid accumulation in the pleural space secondary to pneumonia. It can be uncomplicated (sterile transudate) or complicated (infected empyema). I would monitor for worsening respiratory status, obtain imaging to assess effusion size, and notify the provider. Large or complicated effusions may require thoracentesis or chest tube drainage. I would send fluid for analysis if drained.","Parapneumonic effusion assessment.","intermediate"),
  q("sq-bg7-6",ip,"clinical_judgment","A patient receiving parenteral iron develops wheezing and hypotension.","What reaction is occurring during iron infusion?","Wheezing and hypotension during parenteral iron administration indicate an anaphylactic reaction. I would stop the infusion immediately, administer epinephrine IM, provide supplemental oxygen, establish IV fluid resuscitation, and call for emergency assistance. Some iron formulations carry higher anaphylaxis risk. I would ensure the patient is monitored for at least 30 minutes after any iron infusion.","Iron infusion anaphylaxis management.","advanced"),
  q("sq-bg7-7",ip,"scenario_responses","A patient's family is livestreaming the patient's recovery.","How would you address social media broadcasting in the hospital?","I would approach respectfully: 'I understand wanting to share recovery milestones. However, broadcasting in the hospital can inadvertently capture other patients, staff, or confidential information. Let me help you find a way to share updates that protects everyone's privacy.' I would follow facility social media and recording policies.","Privacy-conscious social media management.","beginner"),
  q("sq-bg7-8",ip,"scenario_responses","A patient newly diagnosed with HIV asks if their life is over.","How would you support a newly diagnosed HIV patient?","I would provide immediate emotional support and factual reassurance: 'I understand this is overwhelming. HIV is no longer a death sentence—with current antiretroviral therapy, people with HIV live long, healthy lives. Let me connect you with our HIV specialist and support resources.' I would screen for depression and suicidality. I would provide accurate, destigmatizing information.","Hope-based education with immediate support connection.","intermediate"),
  q("sq-bg7-9",ws,"prioritization","Your patient's ventilator alarm sounds while you are administering medication to another patient.","How would you respond to a ventilator alarm during another task?","Ventilator alarms take immediate priority as they indicate potential respiratory compromise. I would safely pause my medication administration, respond to the ventilator alarm, assess the patient and ventilator, and address the issue. I would then return to complete the medication administration. Airway and breathing emergencies always supersede other tasks.","Airway priority over all other tasks.","beginner"),
  q("sq-bg7-10",ws,"prioritization","You have a confused patient trying to get out of bed while another patient requests a bedpan.","Which patient do you attend to first?","The confused patient trying to get out of bed is an immediate fall risk. I would attend to them first—either physically assisting them or activating their bed alarm while I quickly help the other patient. If possible, I would call for assistance so both patients can be helped simultaneously. Fall prevention in a confused patient is time-critical.","Immediate fall risk over comfort need.","beginner"),
  q("sq-bg7-11",ws,"delegation","You are mentoring a new CNA on proper vital sign technique.","How would you teach a new CNA proper vital sign measurement?","I would demonstrate proper technique: correct cuff size and placement, proper stethoscope positioning, counting respirations without the patient's awareness, and accurate temperature measurement. I would observe their return demonstration, correct any errors gently, and verify accuracy by comparing their readings to mine initially. I would explain the clinical significance of vital signs so they understand why accuracy matters.","Teaching with demonstration, observation, and significance.","beginner"),
  q("sq-bg7-12",ws,"patient_safety","A patient on anticoagulation therapy falls and hits their head.","What is the critical concern after a head injury in an anticoagulated patient?","An anticoagulated patient who hits their head is at high risk for intracranial hemorrhage because their blood cannot clot normally. I would perform a neurological assessment immediately, check the anticoagulation level, apply ice to any visible injury, keep the patient on bedrest, notify the provider for emergent head CT, and implement neurological monitoring every 15-30 minutes. Even a minor head injury can be life-threatening in anticoagulated patients.","Anticoagulated head injury as a neurosurgical emergency.","advanced"),
  q("sq-bg7-13",ws,"medication_error","A medication is prescribed using an unfamiliar abbreviation.","How would you handle an unfamiliar medication abbreviation?","I would never guess the meaning of an unfamiliar abbreviation. I would contact the prescriber for clarification and request the order be rewritten without abbreviations. I would check the approved abbreviation list. If the abbreviation is on the Joint Commission's Do Not Use list, I would report it through the safety system. Unclear abbreviations have caused serious medication errors.","Zero-tolerance for ambiguous abbreviations.","beginner"),
  q("sq-bg7-14",ws,"handoff_communication","You need to transfer a patient to another facility.","What information is essential for an interfacility transfer?","Essential transfer information includes: patient demographics and insurance, diagnosis and history, current treatments and medications, IV access and infusion details, vital signs trend, allergies, code status, isolation status, pending tests, recent procedures, family contact information, and specific transport safety needs. I would provide copies of relevant medical records and ensure the receiving facility confirms readiness.","Comprehensive interfacility transfer communication.","intermediate"),
  q("sq-bg7-15",ws,"difficult_coworkers","A colleague takes personal calls at the nurses' station during work hours.","How would you address inappropriate personal phone use at work?","I would address it if it affects patient care: 'I noticed you are on personal calls at the station. Patients and families can overhear these conversations, and it can delay response to patient needs. Would you mind taking personal calls in a private area during breaks?' If it is a persistent issue affecting care, I would escalate to the charge nurse.","Professional workspace behavior expectations.","beginner"),
  q("sq-bg7-16",ws,"interdisciplinary_communication","A respiratory therapist and physician disagree about ventilator weaning readiness.","How would you facilitate weaning readiness disagreement?","I would provide my nursing assessment data to support the discussion: 'From nursing assessment, the patient's respiratory parameters are [data]. I notice the RT and physician have different perspectives on readiness. Can we review the weaning protocol criteria together to reach consensus?' I would ensure the decision is made based on objective clinical data rather than opinion.","Data-driven facilitation of clinical disagreements.","intermediate"),
  q("sq-bg7-17",ct,"first_shift","You are given a patient with a condition you barely covered in school.","How would you care for a patient with an unfamiliar diagnosis?","I would quickly research the condition using reliable resources, ask my preceptor for a brief overview, identify key assessment parameters and common complications, and review the patient's orders and care plan. I would be transparent with my preceptor about my knowledge gap and ask more questions than usual. Every unfamiliar diagnosis becomes familiar through clinical experience and study.","Rapid learning approach for unfamiliar diagnoses.","beginner"),
  q("sq-bg7-18",ct,"new_nurse_anxiety","You feel inadequate compared to what you expected nursing to be.","How would you manage reality shock in your first nursing position?","I would recognize reality shock as a normal transition experience. The gap between idealized nursing education and messy real-world practice is disorienting but temporary. I would find a mentor, join a new graduate support group, set realistic expectations, and focus on small daily improvements rather than perfection. I would give myself grace during the learning curve.","Reality shock recognition and management.","beginner"),
  q("sq-bg7-19",ct,"time_management","You need to prepare for a procedure while managing your regular patients.","How would you integrate procedure preparation into your workflow?","I would plan backwards from the procedure time: gather supplies 30 minutes before, complete the consent verification 1 hour before, ensure labs are resulted 2 hours before. I would inform my regular patients about the timing: 'I have a procedure to prepare for at 1300. I will check on you at 1200 and again after the procedure.' Proactive scheduling prevents last-minute scrambling.","Backwards planning for procedure preparation.","beginner"),
  q("sq-bg7-20",ct,"documentation_challenges","You are charting and realize you accidentally documented in the wrong patient's chart.","How would you correct a wrong-patient documentation error?","I would not delete the incorrect entry. I would add a late entry or addendum: 'Entry made in error—this documentation applies to [correct patient name and MRN]. Entry documented in correct chart at [time].' I would document the correct information in the appropriate patient's chart. I would complete an incident report for the wrong-chart documentation. This is a serious error that requires immediate correction.","Wrong-chart documentation correction protocol.","intermediate"),
  q("sq-bg7-21",ct,"critical_thinking_drills","A patient's procalcitonin level is 15 ng/mL.","What does a markedly elevated procalcitonin indicate?","Procalcitonin is a biomarker for bacterial infection, particularly sepsis. A level of 15 (normal <0.1) strongly suggests severe bacterial infection or sepsis. Unlike CRP, procalcitonin is more specific to bacterial causes and does not rise as significantly with viral infections. I would ensure sepsis protocols are activated, blood cultures are drawn, and broad-spectrum antibiotics are initiated.","Procalcitonin as a bacterial infection biomarker.","intermediate"),
  q("sq-bg7-22",ct,"critical_thinking_drills","A patient's partial thromboplastin time is 90 seconds.","What does a significantly prolonged PTT indicate?","A PTT of 90 seconds (normal 25-35) is significantly prolonged. If the patient is on heparin, this is supratherapeutic and requires dose reduction. If not on heparin, it could indicate a coagulation factor deficiency, liver disease, DIC, or an inhibitor. I would assess for bleeding, hold any anticoagulation, notify the provider, and anticipate additional coagulation studies to determine the cause.","Prolonged PTT evaluation.","intermediate"),
  q("sq-bg7-23",pd,"professional_boundaries","You develop romantic feelings for a patient.","How would you handle developing personal feelings for a patient?","I would recognize this as a boundary concern and take action: request reassignment to another patient, discuss the situation with my manager or a trusted mentor, and reflect on maintaining professional boundaries. I would not act on personal feelings toward a patient under my care. If feelings developed after the professional relationship ended, I would still exercise extreme caution per professional guidelines.","Professional boundary management with personal feelings.","intermediate"),
  q("sq-bg7-24",pd,"ethical_dilemmas","You learn that a patient's treatment was delayed due to a system error.","How would you handle learning about a systems-caused treatment delay?","I would report the system error through the appropriate channels—incident report, quality department, and my manager. I would assess whether the delay caused patient harm and document the timeline. I would advocate for system fixes to prevent recurrence. I would be transparent with the patient about the delay if appropriate and if it affected their outcome.","Systems error reporting and patient transparency.","intermediate"),
  q("sq-bg7-25",pd,"workplace_bullying","A colleague frequently takes credit for team accomplishments as their own.","How would you address credit appropriation?","I would make team contributions visible through documentation and email summaries. During meetings, I would use inclusive language: 'Our team worked on this together. My specific contribution was...' If the colleague continued taking individual credit for team work, I would address it privately or discuss it with the manager. Recognition should be shared appropriately.","Making team contributions visible and recognized.","intermediate"),
  q("sq-bg7-26",pd,"advocacy","A patient with a disability cannot access the patient portal.","How would you address technology accessibility barriers?","I would identify alternative ways to provide the patient with their health information: printed summaries, phone calls, or in-person review. I would report the accessibility issue to the IT department and patient experience team. I would advocate for ADA-compliant technology solutions. Every patient deserves equal access to their health information regardless of disability.","Technology accessibility advocacy.","beginner"),
  q("sq-bg7-27",pd,"patient_communication","A teenager refuses to talk to you about their health concerns.","How would you engage a reluctant adolescent patient?","I would respect their autonomy and try different approaches: speak to them as a young adult rather than a child, offer privacy from parents for sensitive discussions, use their interests as conversation starters, and be straightforward without being condescending. I would establish trust by keeping confidential information private within legal limits. Adolescents respond to respect and authenticity.","Adolescent-specific communication strategies.","intermediate"),
  q("sq-bg7-28",cn,"job_offer_negotiation","You want to negotiate for professional development funding.","How would you request professional development in your offer?","I would frame it as institutional investment: 'I am eager to grow within this organization. Would you consider including professional development support—conference attendance, certification exam fees, and CE reimbursement—in my compensation package? Investing in my growth directly benefits patient care quality and my long-term contribution to the team.'","Growth-investment framing for development funding.","beginner"),
  q("sq-bg7-29",cn,"probation_period","You want to volunteer for a committee during your probation.","How would you approach committee involvement as a new nurse?","I would discuss it with my manager first: 'I am interested in joining the falls prevention committee. I want to make sure my clinical performance during probation takes priority, but I also want to contribute to the unit. Would it be appropriate for me to join now, or should I wait until after probation?' Showing initiative while respecting priorities demonstrates maturity.","Initiative-showing with priority awareness.","beginner"),
  q("sq-bg7-30",cn,"career_advancement","You want to develop expertise in pain management.","How would you specialize in pain management nursing?","I would develop comprehensive pain assessment skills, learn about multimodal pain management approaches, understand opioid pharmacology and monitoring, pursue pain management certification, and participate in the hospital's pain management committee. I would study integrative approaches including non-pharmacological interventions. Pain management nursing requires both clinical expertise and compassionate patient advocacy.","Pain management specialization pathway.","intermediate"),
  q("sq-bg7-31",ip,"clinical_judgment","A postpartum patient develops a severe headache, visual changes, and hypertension at 150/100.","What postpartum complication do you suspect?","These symptoms suggest postpartum preeclampsia or eclampsia—which can occur up to 6 weeks after delivery. I would assess deep tendon reflexes for hyperreflexia, check urine protein, administer magnesium sulfate per protocol, prepare for possible seizure, and notify the physician immediately. Postpartum preeclampsia is a medical emergency requiring ICU-level monitoring and aggressive blood pressure management.","Postpartum preeclampsia recognition.","advanced"),
  q("sq-bg7-32",ws,"patient_safety","A patient's Foley catheter is draining cloudy, foul-smelling urine.","What does cloudy, foul-smelling urine indicate?","Cloudy, foul-smelling urine from a catheter suggests catheter-associated urinary tract infection (CAUTI). I would obtain a urine specimen for culture and sensitivity, assess for systemic infection signs (fever, flank pain), notify the provider, and evaluate whether the catheter is still necessary. CAUTI prevention includes early removal, proper insertion technique, and maintaining a closed drainage system.","CAUTI recognition with catheter necessity evaluation.","beginner"),
  q("sq-bg7-33",ct,"critical_thinking_drills","A patient's serum sodium is 160 mEq/L.","What does severe hypernatremia indicate?","Sodium of 160 (normal 135-145) indicates severe hypernatremia, usually from dehydration or diabetes insipidus. Rapid correction can cause cerebral edema. I would provide free water replacement (D5W or oral water), correct no faster than 10-12 mEq/L per 24 hours, monitor neurological status closely, and assess for the underlying cause. Hypernatremia in elderly or debilitated patients carries high mortality.","Hypernatremia with careful correction rate.","advanced"),
  q("sq-bg7-34",pd,"ethical_dilemmas","A patient asks you to help them contact a lawyer for a malpractice case against the hospital.","How would you respond to a patient wanting to sue the hospital?","I would not help or hinder their pursuit. I would say, 'I understand you have concerns about your care. I cannot assist with legal matters, but I can connect you with our patient advocate who can address your concerns. You are also welcome to contact a lawyer independently.' I would not discuss the merits of their case or provide any clinical opinion that could be used in litigation.","Neutral response to legal action requests.","intermediate"),
  q("sq-bg7-35",cn,"career_advancement","You want to develop skills in nursing education.","How would you pursue a nurse educator career?","I would gain clinical expertise in my specialty area first. I would pursue a graduate degree in nursing education. I would develop teaching skills by precepting students and new graduates, creating educational materials, and presenting at unit meetings. I would study educational theory, curriculum development, and learning assessment. I would seek mentorship from experienced nurse educators.","Nurse educator career pathway.","intermediate"),
  q("sq-bg7-36",ip,"behavioral","Tell me about your experience with diverse patient populations.","How has caring for diverse populations shaped your nursing?","During clinical rotations in urban and rural settings, I cared for patients from dozens of cultural backgrounds, socioeconomic levels, and belief systems. Each experience taught me to assess individual needs beyond diagnoses. I learned to ask about cultural practices, food preferences, and spiritual needs. This diversity of experience has made me more adaptable and culturally sensitive.","Cultural competence through diverse clinical experience.","beginner"),
  q("sq-bg7-37",ws,"medication_error","You catch a dosing error in a pediatric medication order.","How would you address a pediatric medication dosing error?","Pediatric dosing errors are especially dangerous because of weight-based calculations. I would verify the child's weight, recalculate the dose per the recommended mg/kg dosing, compare to the ordered dose, and contact the prescriber with my calculation. I would not administer the medication until the dose is verified. I would also check the maximum dose for the child's age and weight.","Weight-based dosing verification for pediatric safety.","intermediate"),
  q("sq-bg7-38",ct,"time_management","You have a patient returning from a test and another being discharged simultaneously.","How would you manage two time-sensitive transitions?","I would delegate the discharge preparation to support staff while I receive and assess the patient returning from the test. Post-procedure assessment has higher clinical priority. I would communicate the brief delay to the discharging patient. Once I confirm the returning patient is stable, I would complete the discharge teaching. Both tasks can be managed within 30-45 minutes with proper delegation.","Priority-based transition management.","beginner"),
  q("sq-bg7-39",pd,"patient_communication","A patient is struggling to accept a new chronic disease diagnosis.","How would you support adjustment to chronic illness?","I would normalize their grief reaction: 'Adjusting to a chronic illness is a process. It is normal to feel angry, sad, or overwhelmed.' I would introduce the stages of adjustment, connect them with support groups and counseling, provide education at their pace, and help them identify meaningful life goals that can be achieved with their condition. I would follow up consistently.","Chronic illness adjustment support.","intermediate"),
  q("sq-bg7-40",cn,"performance_evaluation","You want to include professional development goals in your evaluation.","How would you integrate development goals into your evaluation?","I would prepare specific development goals aligned with both my interests and the unit's needs: 'I would like to pursue CCRN certification this year, join the shared governance committee, and develop my charge nurse skills. These goals support both my career growth and the unit's need for certified nurses and emerging leaders.' Linking personal goals to organizational needs strengthens the request.","Organizationally aligned professional development goals.","beginner"),
  q("sq-bg7-41",ip,"clinical_judgment","A patient with known aortic stenosis becomes lightheaded when standing.","What does positional lightheadedness suggest in aortic stenosis?","In aortic stenosis, the narrowed valve limits cardiac output, especially during activity or position changes. Lightheadedness upon standing indicates inadequate cerebral perfusion. This is a concerning sign suggesting severe stenosis. I would keep the patient on bedrest, implement orthostatic blood pressure monitoring, notify the cardiologist, and ensure the patient does not ambulate unsupervised. Syncope in aortic stenosis can be a precursor to sudden death.","Aortic stenosis symptom progression recognition.","advanced"),
  q("sq-bg7-42",ws,"delegation","You need to delegate monitoring of a patient on a blood transfusion to an LPN.","Can an LPN monitor a blood transfusion?","In many states, LPNs can monitor a blood transfusion after the RN initiates it and completes the first 15-minute assessment. I would verify state and facility policy, ensure the LPN is competent in transfusion reaction recognition, provide specific parameters for notification, and remain immediately available. The RN retains ultimate responsibility for transfusion safety.","Scope-appropriate transfusion monitoring delegation.","intermediate"),
  q("sq-bg7-43",ct,"documentation_challenges","You need to document a patient's advance directive preferences.","How would you document advance directive information?","I would document: whether the patient has an advance directive, where the original document is located, the designated healthcare proxy and their contact information, specific wishes regarding resuscitation, intubation, and artificial nutrition, and any verbal clarifications the patient provides. I would ensure the code status is clearly documented and communicated during every handoff. I would place copies in the chart.","Comprehensive advance directive documentation.","beginner"),
  q("sq-bg7-44",pd,"professional_boundaries","A patient asks you to be their health advocate after discharge.","How would you handle a patient wanting ongoing advocacy?","I would decline while ensuring they have adequate support: 'I am glad I could help during your hospitalization. After discharge, your primary care provider will serve as your health advocate. I can also connect you with a patient navigator or case manager who can provide ongoing support.' I would not establish a post-discharge advocacy relationship as it crosses professional boundaries.","Post-discharge boundary with resource connection.","beginner"),
  q("sq-bg7-45",cn,"career_advancement","You are considering flight nursing.","How would you pursue a flight nursing career?","I would gain extensive emergency or ICU experience (typically 3-5 years minimum), obtain CEN and CCRN certifications, complete flight physiology training, pursue CFRN (Certified Flight Registered Nurse) certification, and develop skills in austere environment care. Physical fitness requirements are strict. Flight nursing combines the highest acuity clinical care with the unique challenges of the transport environment.","Flight nursing career pathway.","advanced"),
  q("sq-bg7-46",ip,"clinical_judgment","A patient being treated for sepsis has a persistently elevated lactate despite fluid resuscitation.","What does a persistently elevated lactate after fluids indicate?","Persistent lactic acidosis despite adequate fluid resuscitation suggests ongoing tissue hypoperfusion or cellular dysfunction. The patient may need vasopressor support to maintain adequate perfusion pressure. I would reassess fluid status, check central venous oxygen saturation if available, notify the provider about treatment failure, and anticipate escalation to vasopressors. Lactate clearance of less than 10% per hour is associated with increased mortality.","Lactate clearance as a sepsis treatment response marker.","advanced"),
  q("sq-bg7-47",ws,"patient_safety","A patient on a heparin drip needs a blood draw.","What special considerations exist for blood draws on heparin?","I would draw blood from the arm opposite the heparin infusion to avoid contamination that would give falsely elevated aPTT results. If drawing from the arm with the infusion, I would stop the heparin for at least 5 minutes and waste adequate blood before collecting the sample. I would note the heparin infusion status on the lab slip. Accurate results depend on proper collection technique.","Heparin-aware blood collection technique.","intermediate"),
  q("sq-bg7-48",ct,"critical_thinking_drills","A patient's reticulocyte count is 8%.","What does an elevated reticulocyte count indicate?","An elevated reticulocyte count (normal 0.5-1.5%) indicates the bone marrow is actively producing new red blood cells, usually in response to blood loss, hemolysis, or treatment for anemia. A reticulocyte count of 8% suggests significant compensatory red cell production. I would correlate with hemoglobin levels, assess for ongoing blood loss, and check for hemolysis markers (LDH, haptoglobin, indirect bilirubin).","Reticulocyte count as a bone marrow response indicator.","intermediate"),
  q("sq-bg7-49",pd,"advocacy","A patient needs a specialized procedure only available at another facility.","How would you facilitate transfer for specialized care?","I would communicate the patient's need to the physician, involve case management for transfer coordination, ensure insurance pre-authorization, coordinate medical records transfer, arrange appropriate transport, and communicate with the receiving facility about the patient's needs. I would keep the patient and family informed throughout the process. Transfer delays for specialized care can significantly affect outcomes.","Interfacility transfer coordination for specialized care.","intermediate"),
  q("sq-bg7-50",ip,"star_examples","Tell me about a time you showed clinical courage.","Describe a situation where you spoke up about patient safety.","I was a student nurse when I noticed that a patient's arterial line waveform had changed from the morning assessment. The experienced nurse dismissed my observation, saying it was normal. I persisted and asked the charge nurse to evaluate. The charge nurse identified that the arterial line had become positional, affecting accuracy of blood pressure readings. The patient's actual blood pressure was significantly lower than what the monitor showed, requiring intervention.","Persistence in patient safety advocacy despite dismissal.","intermediate"),
  q("sq-bg7-51",ws,"handoff_communication","You are giving handoff to a nurse who is visibly distracted by their phone.","How would you address a distracted receiver during handoff?","I would pause and say: 'I want to make sure you get all the important information for safe patient care. Can I have your full attention for the next few minutes?' I would wait for them to put their phone away before continuing. If the behavior persisted, I would document that I provided report and express my concerns about handoff safety to the charge nurse.","Assertive attention request during critical communication.","beginner"),
  q("sq-bg7-52",ct,"new_nurse_anxiety","You are worried about being seen as incompetent if you ask for help.","How would you reframe asking for help?","I would reframe asking for help as a sign of professional maturity and patient safety commitment, not incompetence. The most dangerous nurses are those who do not ask for help when they should. I would approach it proactively: 'I want to provide the best care possible, and consulting with experienced colleagues is part of that.' I would choose appropriate resources and timing for different questions.","Help-seeking as professional strength.","beginner"),
  q("sq-bg7-53",pd,"ethical_dilemmas","A patient in chronic pain is requesting specific controlled substances by name.","How would you handle a patient requesting specific narcotics?","I would not automatically assume drug-seeking behavior. I would assess pain objectively, review the medication history, evaluate the effectiveness of current pain management, and communicate the patient's requests to the provider with my assessment findings. Patients with chronic pain often know which medications work for them. The goal is adequate pain relief while maintaining safety.","Objective pain assessment without stigmatization.","intermediate"),
  q("sq-bg7-54",cn,"probation_period","Your probation includes a competency exam you are nervous about.","How would you prepare for a probation competency exam?","I would identify the competencies being tested and create a study plan. I would practice skills in the simulation lab, review policies and protocols, study pharmacology for my unit's common medications, and take practice exams if available. I would ask my preceptor for areas where I need the most improvement. I would manage test anxiety through preparation, adequate rest, and positive self-talk.","Structured competency exam preparation.","beginner"),
  q("sq-bg7-55",ip,"clinical_judgment","A patient on a continuous insulin drip has blood glucose that drops from 200 to 60 in 2 hours.","What does a rapid glucose drop indicate?","A drop from 200 to 60 in 2 hours while on an insulin drip is dangerously rapid. I would stop the insulin drip immediately, administer dextrose, check blood glucose every 15 minutes, assess for hypoglycemia symptoms, and notify the provider. The drip rate was likely too aggressive or the patient's insulin sensitivity changed. I would not restart the drip at the same rate.","Rapid insulin drip glucose response management.","intermediate"),
  q("sq-bg7-56",ws,"patient_safety","A patient with a new tracheostomy is leaving their room without the emergency tracheostomy kit.","How would you ensure tracheostomy safety during mobility?","I would ensure the patient has a portable emergency kit whenever they leave their room: extra tracheostomy tube (one same size, one smaller), obturator, tracheal hook, scissors, and suction catheter. I would educate the patient and family about the importance of always having emergency supplies available. A tracheostomy emergency without supplies can be fatal within minutes.","Portable tracheostomy emergency kit requirement.","intermediate"),
  q("sq-bg7-57",ct,"critical_thinking_drills","A patient's hemoglobin A1C is 5.5%.","What does a normal A1C indicate for a diabetic patient?","An A1C of 5.5% in a diabetic patient is actually below the typical target of less than 7%, which may be excellent control or could indicate hypoglycemia episodes. I would review the patient's blood glucose logs for patterns of hypoglycemia, assess their medication regimen for appropriateness, and discuss with the provider whether the A1C is reflecting true control or masking dangerous lows.","A1C interpretation considering potential hypoglycemia.","intermediate"),
  q("sq-bg7-58",pd,"patient_communication","A patient with a tracheostomy cannot speak and is frustrated.","How would you facilitate communication with a tracheostomy patient?","I would provide multiple communication tools: writing materials, communication boards, yes/no cards, electronic text-to-speech apps if available. I would be patient and allow time for communication. I would not pretend to understand when I do not. I would consider speech therapy referral for a speaking valve when appropriate. Communication frustration in tracheostomy patients can lead to anxiety and agitation.","Multi-modal communication support for tracheostomy patients.","intermediate"),
  q("sq-bg7-59",cn,"career_advancement","You want to transition into nursing administration.","How would you prepare for nursing administration?","I would develop leadership through charge nurse and committee leadership roles. I would pursue a graduate degree in nursing administration or healthcare management. I would learn about healthcare finance, staffing models, regulatory compliance, and quality metrics. I would develop emotional intelligence and conflict resolution skills. I would seek mentorship from current administrators.","Nursing administration preparation pathway.","intermediate"),
  q("sq-bg7-60",ip,"clinical_judgment","A patient develops signs of compartment syndrome after a cast application.","What are the signs of compartment syndrome and what is the priority?","Compartment syndrome presents with the 5 Ps: Pain out of proportion (especially with passive stretch), Pressure (tense swelling), Paresthesia (numbness/tingling), Pallor, and Pulselessness (late sign). I would notify the orthopedic surgeon STAT for emergent fasciotomy, cut the cast immediately to relieve pressure, elevate the limb to heart level (not above—this can reduce perfusion), and document findings. Delay causes permanent tissue damage.","Compartment syndrome emergency recognition.","advanced"),
  q("sq-bg7-61",ws,"medication_error","A patient's dose was calculated based on an incorrect weight.","How would you address a weight-based dosing error?","I would reweigh the patient immediately, recalculate all weight-based medications, compare to current orders, and notify the provider about any dosing discrepancies. I would hold any medications with significant dosing changes until the provider confirms the corrected doses. I would file an incident report and ensure the correct weight is documented prominently in the chart.","Weight verification for dosing accuracy.","intermediate"),
  q("sq-bg7-62",ct,"documentation_challenges","You need to write a nursing narrative for a complex patient situation.","How would you write an effective nursing narrative?","I would use a structured format: what I observed (objective data), what I assessed (clinical impression), what I did (interventions), what happened (patient response), and what needs to follow (pending actions). I would be specific, use measurable descriptions, include times, and document my clinical reasoning. A good narrative tells the clinical story concisely and completely.","Effective narrative documentation structure.","intermediate"),
  q("sq-bg7-63",pd,"workplace_bullying","A senior nurse publicly humiliates you for a question you asked.","How would you respond to public humiliation?","I would not respond emotionally in the moment. I would address it privately later: 'When you responded to my question that way in front of the team, it was humiliating and discourages me from asking questions in the future, which could affect patient safety.' If the behavior repeated, I would document it and escalate to management. Professional environments should be psychologically safe.","Post-event private confrontation of humiliation.","intermediate"),
  q("sq-bg7-64",cn,"career_advancement","You are interested in psychiatric nursing.","How would you transition to psychiatric nursing?","I would develop therapeutic communication skills, learn about psychiatric medications and their side effects, study de-escalation techniques, obtain PMHN certification, and gain experience through psychiatric unit rotation or floating. I would develop comfort with challenging patient behaviors and learn about involuntary commitment laws. Psychiatric nursing requires strong interpersonal skills and emotional boundaries.","Psychiatric nursing career preparation.","intermediate"),
  q("sq-bg7-65",ip,"scenario_responses","A patient asks why different nurses do things differently.","How would you explain practice variation to a patient?","I would validate their observation: 'That is a great observation. While we follow the same policies and evidence-based practices, individual nurses may have slightly different approaches to certain tasks. What matters most is that you receive safe, effective care. If you notice something that concerns you, please speak up—your safety is our priority.'","Honest practice variation explanation with safety assurance.","beginner"),
  q("sq-bg7-66",ws,"interdisciplinary_communication","You need to communicate urgent lab results to a physician at 3 AM.","How would you handle an urgent 3 AM physician notification?","I would prepare my SBAR before calling: have all relevant information organized, clearly state the urgency, present the abnormal result with context, and have my recommendation ready. I would be concise and professional: 'Good morning, Dr. Lee. I am calling about Mr. Johnson in 312. His potassium just resulted at 6.8. He is currently asymptomatic but I have placed him on cardiac monitoring. Would you like me to initiate the hyperkalemia protocol?'","Organized urgent nighttime physician communication.","beginner"),
  q("sq-bg7-67",ct,"time_management","You realize you forgot to give a scheduled medication 2 hours ago.","How would you handle a medication omission you just discovered?","I would assess whether the medication can still be given safely (within the acceptable window). If yes, I would administer it immediately and adjust the next dose timing. If the window has passed, I would notify the provider. I would document the omission, the action taken, and the rationale. I would file an incident report and analyze why I forgot—then implement a prevention strategy like medication reminders.","Medication omission recovery and prevention.","beginner"),
  q("sq-bg7-68",pd,"ethical_dilemmas","An uninsured patient asks you to order extra supplies so they can take them home.","How would you handle a request for extra hospital supplies?","I would not take hospital supplies without authorization. However, I would understand the underlying need and connect the patient with resources: 'I cannot send extra supplies home, but I can connect you with social services who can help you access wound care supplies, medication assistance, and other resources after discharge.' I would ensure the discharge plan addresses supply needs through proper channels.","Ethical supply management with resource connection.","beginner"),
  q("sq-bg7-69",ip,"clinical_judgment","A patient on dialysis develops chest pain during the procedure.","What are the differential diagnoses for intradialytic chest pain?","Intradialytic chest pain can indicate: air embolism (from the dialysis circuit), acute coronary syndrome (from fluid shifts and electrolyte changes), pericarditis, hemolysis, or hypotension-related angina. I would stop dialysis if severe, assess vital signs, obtain an ECG, check the dialysis circuit for air, and notify the nephrologist immediately. Cardiac enzymes and chest X-ray may be needed.","Intradialytic chest pain differential.","advanced"),
  q("sq-bg7-70",ws,"difficult_coworkers","A nurse from the previous shift left a patient in a soiled bed.","How would you address finding a patient in a neglected state?","I would immediately attend to the patient's needs—clean them, assess skin integrity, and provide comfort. I would document the condition found. I would discuss the concern with the charge nurse, not gossip with other staff. If this is a pattern, I would file a formal concern. Patient neglect is a serious issue that affects both patient safety and dignity.","Immediate patient care followed by formal concern reporting.","intermediate"),
  q("sq-bg7-71",ct,"critical_thinking_drills","A patient's bilirubin is 12 mg/dL.","What does significantly elevated bilirubin indicate?","Total bilirubin of 12 (normal 0.1-1.2) indicates significant jaundice. Causes include liver disease, biliary obstruction, hemolysis, or hepatitis. I would assess for jaundice (skin, sclera), dark urine, and clay-colored stools. I would check direct versus indirect bilirubin to help differentiate the cause. Direct bilirubin elevation suggests obstruction; indirect suggests hemolysis or hepatic dysfunction.","Bilirubin elevation with direct/indirect differentiation.","intermediate"),
  q("sq-bg7-72",pd,"advocacy","A patient needs home health but lives in a rural area with limited services.","How would you advocate for rural patient home health access?","I would research available rural home health agencies, explore telehealth nursing options, coordinate with the patient's primary care provider for remote monitoring, and consider whether family members can be trained for basic care tasks. I would involve social work for creative solutions. Rural healthcare access barriers should not result in inadequate post-discharge support.","Creative rural healthcare access solutions.","intermediate"),
  q("sq-bg7-73",cn,"career_advancement","You want to pursue a career in nursing research.","How would you prepare for a nursing research career?","I would pursue a graduate degree (PhD for research focus), develop research methodology skills, participate in ongoing research studies, publish in nursing journals, present at conferences, and seek research mentorship. I would identify a research focus area aligned with clinical interests. I would apply for research grants and build collaborative relationships with other researchers.","Nursing research career preparation.","advanced"),
  q("sq-bg7-74",ip,"clinical_judgment","A patient on an antifungal medication develops hepatotoxicity.","How would you manage antifungal-related liver injury?","I would hold the antifungal medication, assess liver function tests, monitor for worsening hepatotoxicity signs (jaundice, coagulopathy, encephalopathy), and notify the provider immediately. I would check which antifungal was prescribed—ketoconazole and itraconazole have higher hepatotoxicity risk. Alternative antifungal therapy may be needed. Drug-induced liver injury can progress to fulminant liver failure.","Drug-induced hepatotoxicity management.","advanced"),
  q("sq-bg7-75",ws,"handoff_communication","You need to give report on a patient whose plan of care changed multiple times during your shift.","How would you report on a patient with frequent plan changes?","I would organize my report chronologically for the plan changes: 'The patient started the shift on plan A, but due to [clinical change], the team switched to plan B at 1400. Then at 1700, new test results prompted plan C, which is the current plan.' I would ensure the receiving nurse understands the most current plan and the rationale for each change.","Chronological plan-change communication.","intermediate"),
  q("sq-bg7-76",pd,"professional_boundaries","A patient asks to add you as a beneficiary in their will.","How would you respond to a patient wanting to include you in their will?","I would decline clearly: 'I am deeply touched by your generosity, but accepting this would cross important professional boundaries. My care for you is driven by my commitment to nursing, not by any expectation of reward. If you want to make a charitable contribution, the hospital foundation supports patient care programs.' I would document the interaction and notify my manager.","Clear financial boundary with charitable alternative.","intermediate"),
  q("sq-bg7-77",ct,"new_nurse_anxiety","You feel like you are bothering your preceptor every time you ask a question.","How would you manage guilt about asking your preceptor questions?","I would remind myself that preceptors are selected and often compensated for teaching. Answering questions is literally their job. I would batch non-urgent questions to respect their time. I would try to research answers independently first, then verify with my preceptor. I would express appreciation: 'Thank you for your patience with my questions. I want to make sure I learn the right way.'","Appreciative, organized question-asking.","beginner"),
  q("sq-bg7-78",ip,"clinical_judgment","A patient with myasthenia gravis develops increasing weakness and respiratory difficulty.","What crisis is occurring?","This presentation suggests myasthenic crisis—a life-threatening exacerbation of myasthenia gravis causing respiratory muscle weakness. I would assess respiratory function (FVC, negative inspiratory force), prepare for possible intubation, administer medications as ordered (pyridostigmine or IV immunoglobulin), and notify the neurologist. Myasthenic crisis requires ICU-level respiratory monitoring and often mechanical ventilation.","Myasthenic crisis recognition.","advanced"),
  q("sq-bg7-79",ws,"patient_safety","A patient's epidural catheter appears to have migrated.","How would you assess for epidural catheter migration?","I would check the catheter marking at the skin insertion site and compare to the documented initial position. I would assess for changes in pain control, new symptoms (numbness, weakness, headache), and check vital signs. I would not manipulate or reposition the catheter—this is an anesthesia provider responsibility. I would notify the anesthesia team immediately for evaluation.","Epidural catheter migration assessment.","intermediate"),
  q("sq-bg7-80",cn,"performance_evaluation","You want to advocate for a leadership role during your evaluation.","How would you position yourself for a leadership role?","I would present evidence of my leadership readiness: 'I have demonstrated leadership by [specific examples], received positive feedback from colleagues about my clinical guidance, and completed charge nurse training. I am ready for a formal leadership role. What steps would you recommend for me to take on charge responsibilities or join the unit leadership team?' Specific evidence is more compelling than vague requests.","Evidence-based leadership role advocacy.","intermediate"),
];
